mapper.select:
SELECT DISTINCT TOP 10 A.DOC_NO AS docNo, A.DOC_DATE AS DOC_DATE, CAST(A.DOC_DATE AS NVARCHAR(10)) AS createDate, ISNULL(C.ADMIN_UNIT_CODE, ' ') AS departmentNo, ISNULL(C.ADMIN_UNIT_NAME, ' ') AS departmentName, ISNULL(D.EMPLOYEE_CODE, ' ') AS employeeNo, ISNULL(D.EMPLOYEE_NAME, ' ') AS employeeName, '' AS customerNo, '' AS customerName, '' AS supplierNo, '' AS supplierName FROM TRANSACTION_DOC AS A INNER JOIN PLANT ON PLANT.PLANT_ID = A.Owner_Org_ROid LEFT JOIN ADMIN_UNIT AS C ON C.ADMIN_UNIT_ID = A.Owner_Dept LEFT JOIN EMPLOYEE AS D ON D.EMPLOYEE_ID = A.Owner_Emp INNER JOIN TRANSACTION_DOC_D AS B ON B.TRANSACTION_DOC_ID = A.TRANSACTION_DOC_ID INNER JOIN ITEM ON B.ITEM_ID = ITEM.ITEM_BUSINESS_ID WHERE PLANT.PLANT_CODE = '1' AND A.ApproveStatus = 'N' AND A.CATEGORY = '11' AND A.STOCK_ACTION = -1
AND A.DOC_NO LIKE concat('%',#{docNo},'%')
AND CAST(A.DOC_DATE AS NVARCHAR(10)) > #{startDate}
AND CAST(A.DOC_DATE AS NVARCHAR(10)) < #{endDate}
AND (C.ADMIN_UNIT_CODE LIKE concat('%',#{department},'%') OR C.ADMIN_UNIT_NAME LIKE concat('%',#{department},'%'))
AND (D.EMPLOYEE_CODE LIKE concat('%',#{employee},'%') OR D.EMPLOYEE_NAME LIKE concat('%',#{employee},'%'))
UNION ALL SELECT DISTINCT TOP 10 A.DOC_NO AS docNo, A.DOC_DATE AS DOC_DATE, CAST(A.DOC_DATE AS NVARCHAR(10)) AS createDate, ISNULL(C.ADMIN_UNIT_CODE, ' ') AS departmentNo, ISNULL(C.ADMIN_UNIT_NAME, ' ') AS departmentName, ISNULL(D.EMPLOYEE_CODE, ' ') AS employeeNo, ISNULL(D.EMPLOYEE_NAME, ' ') AS employeeName, '' AS customerNo, '' AS customerName, '' AS supplierNo, '' AS supplierName FROM STOCK_REQUISITION AS A INNER JOIN PLANT ON PLANT.PLANT_ID = A.Owner_Org_ROid LEFT JOIN ADMIN_UNIT AS C ON C.ADMIN_UNIT_ID = A.Owner_Dept LEFT JOIN EMPLOYEE AS D ON D.EMPLOYEE_ID = A.Owner_Emp INNER JOIN STOCK_REQUISITION_D AS B ON B.STOCK_REQUISITION_ID = A.STOCK_REQUISITION_ID INNER JOIN ITEM ON B.ITEM_ID = ITEM.ITEM_BUSINESS_ID WHERE PLANT.PLANT_CODE = '1' AND A.ApproveStatus = 'Y' AND B.[CLOSE] = '0'
AND A.DOC_NO LIKE concat('%',#{docNo},'%')
AND CAST(A.DOC_DATE AS NVARCHAR(10)) > #{startDate}
AND CAST(A.DOC_DATE AS NVARCHAR(10)) < #{endDate}
AND (C.ADMIN_UNIT_CODE LIKE concat('%',#{department},'%') OR C.ADMIN_UNIT_NAME LIKE concat('%',#{department},'%'))
AND (D.EMPLOYEE_CODE LIKE concat('%',#{employee},'%') OR D.EMPLOYEE_NAME LIKE concat('%',#{employee},'%'))
ORDER BY DOC_DATE DESC, docNo ASC

SELECT DISTINCT A.DOC_NO AS docNo, CAST(A.DOC_DATE AS NVARCHAR(10)) AS docDate, ISNULL(C.ADMIN_UNIT_CODE, ' ') AS departmentNo, ISNULL(C.ADMIN_UNIT_NAME, ' ') AS departmentName, ISNULL(D.EMPLOYEE_CODE, ' ') AS employeeNo, ISNULL(D.EMPLOYEE_NAME, ' ') AS employeeName, '' AS customerNo, '' AS customerName, '' AS supplierNo, '' AS supplierName FROM TRANSFER_DOC AS A INNER JOIN TRANSFER_DOC_D AS B ON B.TRANSFER_DOC_ID = A.TRANSFER_DOC_ID INNER JOIN PLANT ON PLANT.PLANT_ID = A.Owner_Org_ROid LEFT JOIN ADMIN_UNIT AS C ON C.ADMIN_UNIT_ID = A.Owner_Dept LEFT JOIN EMPLOYEE AS D ON D.EMPLOYEE_ID = A.Owner_Emp INNER JOIN ITEM ON B.ITEM_ID = ITEM.ITEM_BUSINESS_ID WHERE PLANT.PLANT_CODE = '1' AND A.ApproveStatus = 'N' AND A.CATEGORY = '16' AND B.BUSINESS_QTY > '0'
AND A.DOC_NO like concat('%',#{docNo},'%')
AND (C.ADMIN_UNIT_CODE like concat('%',#{department},'%') or C.ADMIN_UNIT_NAME like concat('%',#{department},'%'))
AND (D.EMPLOYEE_CODE like concat('%',#{employee},'%') or D.EMPLOYEE_NAME like concat('%',#{employee},'%'))
and A.DOC_DATE <= #{endDate}
and A.DOC_DATE >= #{startDate}
UNION ALL SELECT DISTINCT A.DOC_NO AS docNo, CAST(A.DOC_DATE AS NVARCHAR(10)) AS docDate, ISNULL(C.ADMIN_UNIT_CODE, ' ') AS departmentNo, ISNULL(C.ADMIN_UNIT_NAME, ' ') AS departmentName, ISNULL(D.EMPLOYEE_CODE, ' ') AS employeeNo, ISNULL(D.EMPLOYEE_NAME, ' ') AS employeeName, '' AS customerNo, '' AS customerName, '' AS supplierNo, '' AS supplierName FROM TRANSFER_REQUISITION AS A INNER JOIN TRANSFER_REQUISITION_D AS B ON A.TRANSFER_REQUISITION_ID = B.TRANSFER_REQUISITION_ID INNER JOIN PLANT ON PLANT.PLANT_ID = A.FROM_PLANT_ID LEFT JOIN ADMIN_UNIT AS C ON C.ADMIN_UNIT_ID = A.Owner_Dept LEFT JOIN EMPLOYEE AS D ON D.EMPLOYEE_ID = A.Owner_Emp INNER JOIN ITEM ON B.ITEM_ID = ITEM.ITEM_BUSINESS_ID WHERE PLANT.PLANT_CODE = '1' AND A.ApproveStatus = 'Y' AND A.CATEGORY = '1J' AND B.[CLOSE] = '0' AND B.BUSINESS_QTY > B.TRANS_OUT_BUSINESS_QTY
AND A.DOC_NO like concat('%',#{docNo},'%')
AND (C.ADMIN_UNIT_CODE like concat('%',#{department},'%') or C.ADMIN_UNIT_NAME like concat('%',#{department},'%'))
AND (D.EMPLOYEE_CODE like concat('%',#{employee},'%') or D.EMPLOYEE_NAME like concat('%',#{employee},'%'))
and A.DOC_DATE <= #{endDate}
and A.DOC_DATE >= #{startDate}
ORDER BY docDate DESC, docNo ASC

SELECT DISTINCT A.DOC_NO AS docNo,A.DOC_ID AS docId,B.TRANSFER_DOC_D_ID AS docDId,U.UNIT_CODE unitCode, U.UNIT_NAME unitName, FC.WAREHOUSE_CODE fromWarehouseCode,TC.WAREHOUSE_CODE toWarehouseCode, D.ITEM_CODE itemCode,D.ITEM_NAME itemName,D.ITEM_SPECIFICATION itemSpec, FP.PLANT_CODE AS fromShjg, TP.PLANT_CODE AS toShjg,B.SequenceNumber xh FROM TRANSFER_DOC AS A LEFT JOIN TRANSFER_DOC_D AS B ON B.TRANSFER_DOC_ID=A.TRANSFER_DOC_ID LEFT JOIN PLANT FP ON FP.PLANT_ID = A.Owner_Org_ROid LEFT JOIN PLANT TP ON TP.PLANT_ID = A.TO_PLANT_ID LEFT JOIN ITEM ON B.ITEM_ID=ITEM.ITEM_BUSINESS_ID LEFT JOIN WAREHOUSE FC ON B.FROM_WAREHOUSE_ID = FC.WAREHOUSE_ID LEFT JOIN WAREHOUSE TC ON B.TO_WAREHOUSE_ID = TC.WAREHOUSE_ID LEFT JOIN ITEM D ON D.ITEM_BUSINESS_ID = B.ITEM_ID LEFT JOIN ITEM_PLANT Z ON Z.ITEM_ID = D.ITEM_BUSINESS_ID LEFT JOIN UNIT U ON D.STOCK_UNIT_ID = U.UNIT_ID WHERE B.BUSINESS_QTY - B.TRANSFERED_BUSINESS_QTY > 0
AND A.DOC_ID = #{docId}
AND A.DOC_NO = #{docNo}
AND D.ITEM_CODE = #{itemCode}
ORDER BY D.ITEM_CODE
